export const getAdminListCrawlerJobsUrl = (params?: AdminListCrawlerJobsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/admin/crawler/jobs?${stringifiedParams}` : `/api/v1/admin/crawler/jobs`
}

